.otodo {
  position: relative;
}

.otodo__toast {
  position: fixed;
  bottom: 1.5rem;
  left: 50%;
  transform: translateX(-50%);
  background: #ef4444;
  color: white;
  padding: 0.5rem 1rem;
  border-radius: 0.375rem;
  font-size: 0.8125rem;
  z-index: 100;
  animation: toast-in 0.2s ease;
}

@keyframes toast-in {
  from { opacity: 0; transform: translateX(-50%) translateY(0.5rem); }
  to { opacity: 1; transform: translateX(-50%) translateY(0); }
}

.otodo__list {
  display: flex;
  flex-direction: column;
  gap: 0.375rem;
}

.otodo__item {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  padding: 0.625rem 0.75rem;
  border: 1px solid #e5e7eb;
  border-radius: 0.375rem;
  transition: opacity 0.2s;
}

.otodo__item--done .otodo__text {
  text-decoration: line-through;
  color: #9ca3af;
}

.otodo__item--syncing {
  opacity: 0.7;
}

.otodo__text {
  flex: 1;
  font-size: 0.875rem;
}

.otodo__sync {
  font-size: 0.75rem;
  color: #3b82f6;
  animation: spin 1s linear infinite;
}

@keyframes spin {
  to { transform: rotate(360deg); }
}

.otodo__delete {
  background: none;
  border: none;
  color: #d1d5db;
  cursor: pointer;
  font-size: 0.875rem;
}

.otodo__delete:hover:not(:disabled) {
  color: #ef4444;
}

.otodo__delete:disabled {
  cursor: not-allowed;
}

