import { render, screen, fireEvent, waitFor } from '@testing-library/react';
import '@testing-library/jest-dom';
import React from 'react';

let fetchMock: jest.Mock;

beforeEach(() => {
  fetchMock = jest.fn(() => Promise.resolve({ ok: true, json: () => Promise.resolve({}) }));
  global.fetch = fetchMock;
});

afterEach(() => {
  jest.restoreAllMocks();
});

import App from './App';

describe('Optimistic Updates', () => {
  it('renders all todos', () => {
    render(<App />);
    expect(screen.getByTestId('todo-1')).toBeInTheDocument();
    expect(screen.getByTestId('todo-5')).toBeInTheDocument();
  });

  it('optimistically toggles checkbox', () => {
    render(<App />);
    const cb = screen.getByTestId('toggle-1') as HTMLInputElement;
    expect(cb.checked).toBe(false);
    fireEvent.click(cb);
    expect(cb.checked).toBe(true);
  });

  it('sends PATCH/PUT on toggle', async () => {
    render(<App />);
    fireEvent.click(screen.getByTestId('toggle-1'));
    await waitFor(() => {
      expect(fetchMock).toHaveBeenCalled();
    });
  });

  it('rolls back on toggle failure', async () => {
    fetchMock.mockRejectedValue(new Error('fail'));
    render(<App />);
    const cb = screen.getByTestId('toggle-1') as HTMLInputElement;
    expect(cb.checked).toBe(false);
    fireEvent.click(cb);
    // Optimistic: checked
    expect(cb.checked).toBe(true);
    // After rejection: rolled back
    await waitFor(() => {
      expect(cb.checked).toBe(false);
    });
  });

  it('shows error toast on failure', async () => {
    fetchMock.mockRejectedValue(new Error('fail'));
    render(<App />);
    fireEvent.click(screen.getByTestId('toggle-1'));
    await waitFor(() => {
      expect(screen.getByTestId('error-toast')).toBeInTheDocument();
    });
  });

  it('optimistically deletes a todo', () => {
    render(<App />);
    expect(screen.getByTestId('todo-3')).toBeInTheDocument();
    fireEvent.click(screen.getByTestId('delete-3'));
    expect(screen.queryByTestId('todo-3')).not.toBeInTheDocument();
  });

  it('shows syncing indicator during request', () => {
    fetchMock.mockReturnValue(new Promise(() => {})); // never resolves
    render(<App />);
    fireEvent.click(screen.getByTestId('toggle-1'));
    expect(screen.getByTestId('syncing-1')).toBeInTheDocument();
  });
});

