import React, { useState, useCallback } from 'react';
import './styles.css';

interface Todo {
  id: number;
  text: string;
  completed: boolean;
}

interface TodoListProps {
  initialTodos: Todo[];
  apiUrl: string;
}

export const TodoList: React.FC<TodoListProps> = ({ initialTodos, apiUrl }) => {
  const [todos, setTodos] = useState<Todo[]>(initialTodos);
  const [syncing, setSyncing] = useState<Set<number>>(new Set());
  const [errorMsg, setErrorMsg] = useState<string | null>(null);

  const showError = useCallback((msg: string) => {
    setErrorMsg(msg);
    setTimeout(() => setErrorMsg(null), 3000);
  }, []);

  const handleToggle = useCallback(async (id: number) => {
    const prevTodos = [...todos];
    const todo = todos.find(t => t.id === id);
    if (!todo) return;

    // Optimistic update
    setTodos(prev => prev.map(t => t.id === id ? { ...t, completed: !t.completed } : t));
    setSyncing(prev => new Set(prev).add(id));

    try {
      const res = await fetch(`${apiUrl}/${id}`, {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ completed: !todo.completed }),
      });
      if (!res.ok) throw new Error('Failed');
    } catch {
      setTodos(prevTodos);
      showError('Failed to update — changes reverted');
    } finally {
      setSyncing(prev => {
        const next = new Set(prev);
        next.delete(id);
        return next;
      });
    }
  }, [todos, apiUrl, showError]);

  const handleDelete = useCallback(async (id: number) => {
    const prevTodos = [...todos];

    setTodos(prev => prev.filter(t => t.id !== id));
    setSyncing(prev => new Set(prev).add(id));

    try {
      const res = await fetch(`${apiUrl}/${id}`, { method: 'DELETE' });
      if (!res.ok) throw new Error('Failed');
    } catch {
      setTodos(prevTodos);
      showError('Failed to delete — changes reverted');
    } finally {
      setSyncing(prev => {
        const next = new Set(prev);
        next.delete(id);
        return next;
      });
    }
  }, [todos, apiUrl, showError]);

  return (
    <div className="otodo">
      {errorMsg && (
        <div data-testid="error-toast" className="otodo__toast">{errorMsg}</div>
      )}

      <div data-testid="todo-list" className="otodo__list">
        {todos.map(todo => (
          <div
            key={todo.id}
            data-testid={`todo-${todo.id}`}
            className={`otodo__item${todo.completed ? ' otodo__item--done' : ''}${syncing.has(todo.id) ? ' otodo__item--syncing' : ''}`}
          >
            <input
              data-testid={`toggle-${todo.id}`}
              type="checkbox"
              checked={todo.completed}
              onChange={() => handleToggle(todo.id)}
              disabled={syncing.has(todo.id)}
            />
            <span className="otodo__text">{todo.text}</span>
            {syncing.has(todo.id) && (
              <span data-testid={`syncing-${todo.id}`} className="otodo__sync">⟳</span>
            )}
            <button
              data-testid={`delete-${todo.id}`}
              className="otodo__delete"
              onClick={() => handleDelete(todo.id)}
              disabled={syncing.has(todo.id)}
            >
              ✕
            </button>
          </div>
        ))}
      </div>
    </div>
  );
};
